function useCountUp(target, duration = 1200, trigger) {
  const [count, setCount] = useState(0);
  useEffect(() => {
    if (!trigger) return;
    let start = null;
    const num = parseFloat(target.replace(/[^0-9.]/g, ""));
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / duration, 1);
      setCount(Math.floor(p * num));
      if (p < 1) requestAnimationFrame(step); else setCount(num);
    };
    requestAnimationFrame(step);
  }, [trigger]);
  return count;
}

function StatCard({ value, label, sub }) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVisible(true); }, { threshold: 0.3 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  const num    = useCountUp(value, 1200, visible);
  const prefix = value.startsWith("+") ? "+" : "";
  const suffix = value.includes("%") ? "%" : "";
  return (
    <div ref={ref} className="stat-card">
      <div className="stat-value">{prefix}{num.toLocaleString()}{suffix}</div>
      <div className="stat-label">{label}</div>
      <div className="stat-sub">{sub}</div>
    </div>
  );
}

function scrollTo(id) {
  document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
}

